-- ============================================================================
-- Quiz Seed: 2 Thessalonians (Chapters 1–3)
-- 3 difficulties × 3 chapters = 48 total questions
--   kids:   3 per chapter  =  9
--   teens:  5 per chapter  = 15
--   adults: 8 per chapter  = 24
-- ============================================================================

-- ═══ 2 Thessalonians Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Thessalonians', 1, 'kids', 1, 'Who wrote 2 Thessalonians?', 'Paul, Silvanus, and Timothy', 'Peter and John', 'James and Jude', 'Luke and Mark', 'a', '2 Thessalonians 1:1 — "Paul, and Silvanus, and Timotheus, unto the church of the Thessalonians."'),
('2 Thessalonians', 1, 'kids', 2, 'What did Paul say was growing in the Thessalonians?', 'Their faith', 'Their money', 'Their buildings', 'Their animals', 'a', '2 Thessalonians 1:3 — "your faith groweth exceedingly."'),
('2 Thessalonians', 1, 'kids', 3, 'Who will Jesus punish when He comes back?', 'Those who do not obey the gospel', 'Only the Roman soldiers', 'All animals', 'The angels', 'a', '2 Thessalonians 1:8 — "taking vengeance on them that know not God, and that obey not the gospel of our Lord Jesus Christ."'),
-- Teens
('2 Thessalonians', 1, 'teens', 1, 'What two things does Paul thank God for regarding the Thessalonians?', 'Their growing faith and abounding love toward each other', 'Their wealth and influence', 'Their building program and membership growth', 'Their obedience to Jewish law and temple attendance', 'a', '2 Thessalonians 1:3 — "your faith groweth exceedingly, and the charity of every one of you all toward each other aboundeth."'),
('2 Thessalonians', 1, 'teens', 2, 'What does Paul say is evidence that God''s judgment is righteous?', 'The Thessalonians'' patient endurance of persecutions and tribulations shows they are counted worthy of the kingdom', 'Their financial prosperity proves God''s favor', 'Their large church proves they are righteous', 'Their lack of problems proves God''s blessing', 'a', '2 Thessalonians 1:4-5 — "your patience and faith in all your persecutions and tribulations… a manifest token of the righteous judgment of God, that ye may be counted worthy of the kingdom."'),
('2 Thessalonians', 1, 'teens', 3, 'How will Jesus be revealed from heaven?', 'With His mighty angels in flaming fire', 'On a white horse with a sword', 'Quietly and secretly', 'Through a prophet''s announcement', 'a', '2 Thessalonians 1:7 — "the Lord Jesus shall be revealed from heaven with his mighty angels, In flaming fire."'),
('2 Thessalonians', 1, 'teens', 4, 'What punishment awaits those who do not obey the gospel?', 'Everlasting destruction from the presence of the Lord and the glory of His power', 'Temporary suffering followed by restoration', 'Simply ceasing to exist', 'Being sent to a different planet', 'a', '2 Thessalonians 1:9 — "Who shall be punished with everlasting destruction from the presence of the Lord, and from the glory of his power."'),
('2 Thessalonians', 1, 'teens', 5, 'What does Paul pray will be glorified in the Thessalonians?', 'The name of our Lord Jesus Christ, and they in Him', 'Their own reputations and achievements', 'The name of their city', 'The fame of their church', 'a', '2 Thessalonians 1:12 — "That the name of our Lord Jesus Christ may be glorified in you, and ye in him."'),
-- Adults
('2 Thessalonians', 1, 'adults', 1, 'What does Paul say is a righteous thing with God?', 'To recompense tribulation to them that trouble the Thessalonians, and to give rest to the troubled', 'To bless all people equally regardless of their actions', 'To withhold judgment indefinitely', 'To allow the wicked to prosper without consequence', 'a', '2 Thessalonians 1:6-7 — "it is a righteous thing with God to recompense tribulation to them that trouble you; And to you who are troubled rest with us."'),
('2 Thessalonians', 1, 'adults', 2, 'What two groups does Christ take vengeance on at His coming?', 'Those who know not God and those who obey not the gospel of our Lord Jesus Christ', 'Only the Jews who rejected Him and the Romans who crucified Him', 'Only false teachers and their followers', 'Only demons and fallen angels', 'a', '2 Thessalonians 1:8 — "In flaming fire taking vengeance on them that know not God, and that obey not the gospel of our Lord Jesus Christ."'),
('2 Thessalonians', 1, 'adults', 3, 'When does Paul say Christ will be admired?', 'When He comes to be glorified in His saints and admired in all them that believe in that day', 'When He establishes an earthly kingdom', 'When He appears to the Roman emperor', 'When the temple is rebuilt', 'a', '2 Thessalonians 1:10 — "When he shall come to be glorified in his saints, and to be admired in all them that believe… in that day."'),
('2 Thessalonians', 1, 'adults', 4, 'What does Paul pray God would count them worthy of?', 'Their calling, and fulfil all the good pleasure of His goodness and the work of faith with power', 'Their sacrifices and offerings', 'Their leadership position in the church', 'Their Hebrew ancestry', 'a', '2 Thessalonians 1:11 — "that our God would count you worthy of this calling, and fulfil all the good pleasure of his goodness, and the work of faith with power."'),
('2 Thessalonians', 1, 'adults', 5, 'What is the basis for Paul''s prayer for the Thessalonians?', 'According to the grace of our God and the Lord Jesus Christ', 'According to their works and merit', 'According to apostolic authority', 'According to prophecy and signs', 'a', '2 Thessalonians 1:12 — "according to the grace of our God and the Lord Jesus Christ."'),
('2 Thessalonians', 1, 'adults', 6, 'How does Paul describe the Thessalonians'' persecutions?', 'They endure them patiently, and Paul boasts about them in the churches of God', 'They fled from them to other cities', 'They fought back against their persecutors', 'They complained bitterly to Paul', 'a', '2 Thessalonians 1:4 — "we ourselves glory in you in the churches of God for your patience and faith in all your persecutions and tribulations that ye endure."'),
('2 Thessalonians', 1, 'adults', 7, 'What does "everlasting destruction from the presence of the Lord" imply theologically?', 'Eternal separation from God''s beneficial presence — the punishment is both the loss of God''s presence and the experience of His wrath', 'Annihilation of the soul', 'Temporary punishment followed by reconciliation', 'Physical destruction of the body only', 'a', '2 Thessalonians 1:9 — "punished with everlasting destruction from the presence of the Lord, and from the glory of his power."'),
('2 Thessalonians', 1, 'adults', 8, 'What does Paul''s statement "our testimony among you was believed" in verse 10 connect to?', 'It connects the Thessalonians'' faith to their participation in Christ''s future glory — they believed, so they will be among those in whom He is glorified', 'It proves Paul was a reliable witness in court', 'It refers to miracles Paul performed among them', 'It means they accepted his letter as Scripture', 'a', '2 Thessalonians 1:10 — "because our testimony among you was believed."');

-- ═══ 2 Thessalonians Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Thessalonians', 2, 'kids', 1, 'What did Paul tell the Thessalonians not to be?', 'Shaken in mind or troubled, as if the day of Christ had already come', 'Scared of animals', 'Lazy at school', 'Mean to their parents', 'a', '2 Thessalonians 2:2 — "That ye be not soon shaken in mind, or be troubled… as that the day of Christ is at hand."'),
('2 Thessalonians', 2, 'kids', 2, 'Who is the "man of sin" who will try to deceive people?', 'A wicked person who opposes God and sits in God''s temple claiming to be God', 'A Roman soldier', 'A wild animal', 'A mean teacher', 'a', '2 Thessalonians 2:3-4 — "that man of sin be revealed, the son of perdition; Who opposeth and exalteth himself above all that is called God."'),
('2 Thessalonians', 2, 'kids', 3, 'What did Paul tell believers to stand fast and hold?', 'The traditions (teachings) they had been taught', 'Their money tightly', 'Each other''s hands', 'Their breath', 'a', '2 Thessalonians 2:15 — "stand fast, and hold the traditions which ye have been taught."'),
-- Teens
('2 Thessalonians', 2, 'teens', 1, 'What must happen before the day of Christ comes?', 'A falling away (apostasy) must come first and the man of sin must be revealed', 'All nations must become Christian', 'The temple must be rebuilt in Jerusalem', 'Every person on earth must hear the gospel', 'a', '2 Thessalonians 2:3 — "that day shall not come, except there come a falling away first, and that man of sin be revealed, the son of perdition."'),
('2 Thessalonians', 2, 'teens', 2, 'What will the Lord Jesus do to the wicked one?', 'Consume him with the spirit of His mouth and destroy him with the brightness of His coming', 'Imprison him for a thousand years', 'Reform and convert him', 'Send him to a distant land', 'a', '2 Thessalonians 2:8 — "whom the Lord shall consume with the spirit of his mouth, and shall destroy with the brightness of his coming."'),
('2 Thessalonians', 2, 'teens', 3, 'What deception will come upon those who refuse to love the truth?', 'God shall send them strong delusion, that they should believe a lie', 'They will simply remain ignorant', 'They will be physically blinded', 'They will forget everything they know', 'a', '2 Thessalonians 2:11 — "God shall send them strong delusion, that they should believe a lie."'),
('2 Thessalonians', 2, 'teens', 4, 'What is currently restraining the man of sin?', 'A restrainer ("he who now letteth") who will be taken out of the way first', 'The Roman Empire', 'The Jewish temple', 'A powerful angel', 'a', '2 Thessalonians 2:7 — "he who now letteth will let, until he be taken out of the way."'),
('2 Thessalonians', 2, 'teens', 5, 'What did God choose the Thessalonians to through from the beginning?', 'Salvation through sanctification of the Spirit and belief of the truth', 'Earthly prosperity and political power', 'Exemption from all suffering', 'Leadership over all other churches', 'a', '2 Thessalonians 2:13 — "God hath from the beginning chosen you to salvation through sanctification of the Spirit and belief of the truth."'),
-- Adults
('2 Thessalonians', 2, 'adults', 1, 'What does the man of sin do in the temple of God?', 'He sits in the temple of God, showing himself that he is God', 'He offers sacrifices to pagan idols', 'He destroys the temple completely', 'He locks the doors and keeps everyone out', 'a', '2 Thessalonians 2:4 — "he as God sitteth in the temple of God, shewing himself that he is God."'),
('2 Thessalonians', 2, 'adults', 2, 'What accompanies the working of Satan through the lawless one?', 'All power, signs, and lying wonders, and all deceivableness of unrighteousness', 'True miracles that cannot be distinguished from God''s', 'Political manipulation and military conquest only', 'Scholarly arguments and philosophical reasoning', 'a', '2 Thessalonians 2:9-10 — "whose coming is after the working of Satan with all power and signs and lying wonders, And with all deceivableness of unrighteousness."'),
('2 Thessalonians', 2, 'adults', 3, 'Why does God send strong delusion to the unbelievers?', 'Because they received not the love of the truth that they might be saved — it is judicial judgment on willful rejection', 'Because God wants them to perish', 'Because they never had the chance to hear the truth', 'Because they were predestined to be lost', 'a', '2 Thessalonians 2:10-11 — "because they received not the love of the truth, that they might be saved. And for this cause God shall send them strong delusion."'),
('2 Thessalonians', 2, 'adults', 4, 'What does "the mystery of iniquity doth already work" mean?', 'The spirit and principle of lawlessness was already secretly active in Paul''s day, awaiting full manifestation', 'A specific crime was being committed in the church', 'The Roman Empire was declining', 'Jewish false teachers were already in Thessalonica', 'a', '2 Thessalonians 2:7 — "the mystery of iniquity doth already work: only he who now letteth will let, until he be taken out of the way."'),
('2 Thessalonians', 2, 'adults', 5, 'What two means of teaching does Paul reference in verse 15?', 'By word (oral teaching) and by epistle (written letter) — both are authoritative apostolic tradition', 'By parables and by allegories', 'By miracles and by visions', 'By fasting and by prayer', 'a', '2 Thessalonians 2:15 — "hold the traditions which ye have been taught, whether by word, or our epistle."'),
('2 Thessalonians', 2, 'adults', 6, 'What does Paul pray God would do for the Thessalonians'' hearts?', 'Comfort their hearts and stablish them in every good word and work', 'Reveal to them the date of Christ''s return', 'Remove all their earthly troubles', 'Give them positions of authority', 'a', '2 Thessalonians 2:16-17 — "comfort your hearts, and stablish you in every good word and work."'),
('2 Thessalonians', 2, 'adults', 7, 'What is the ultimate fate of all who did not believe the truth?', 'That they all might be damned who believed not the truth, but had pleasure in unrighteousness', 'They will have a second chance after death', 'They will be given more time to repent', 'They will simply cease to exist', 'a', '2 Thessalonians 2:12 — "That they all might be damned who believed not the truth, but had pleasure in unrighteousness."'),
('2 Thessalonians', 2, 'adults', 8, 'How does Paul describe God''s love toward the Thessalonians?', 'God loved them and gave them everlasting consolation and good hope through grace', 'God tested them severely to prove their faith', 'God remained distant until they proved themselves', 'God offered conditional love based on their obedience', 'a', '2 Thessalonians 2:16 — "God, even our Father, which hath loved us, and hath given us everlasting consolation and good hope through grace."');

-- ═══ 2 Thessalonians Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('2 Thessalonians', 3, 'kids', 1, 'What does Paul say people should do instead of being idle?', 'Work quietly and earn their own bread', 'Sleep all day', 'Beg from others', 'Complain about everything', 'a', '2 Thessalonians 3:12 — "that with quietness they work, and eat their own bread."'),
('2 Thessalonians', 3, 'kids', 2, 'What should we not be weary of doing?', 'Well doing (doing good)', 'Eating', 'Playing', 'Sleeping', 'a', '2 Thessalonians 3:13 — "be not weary in well doing."'),
('2 Thessalonians', 3, 'kids', 3, 'What did Paul ask the Thessalonians to pray for?', 'That the word of the Lord would spread quickly', 'That Paul would become rich', 'That it would stop raining', 'That Rome would fall', 'a', '2 Thessalonians 3:1 — "pray for us, that the word of the Lord may have free course, and be glorified."'),
-- Teens
('2 Thessalonians', 3, 'teens', 1, 'What rule did Paul give about those who refuse to work?', 'If any would not work, neither should he eat', 'Give them extra food to encourage them', 'Appoint them as teachers instead', 'Send them to another church', 'a', '2 Thessalonians 3:10 — "if any would not work, neither should he eat."'),
('2 Thessalonians', 3, 'teens', 2, 'What did Paul say about disorderly brethren?', 'Withdraw from them, but do not count them as enemies — admonish them as brothers', 'Expel them permanently from the church', 'Ignore them completely', 'Give them leadership responsibilities', 'a', '2 Thessalonians 3:6,14-15 — "withdraw yourselves from every brother that walketh disorderly… yet count him not as an enemy, but admonish him as a brother."'),
('2 Thessalonians', 3, 'teens', 3, 'How did Paul set an example for the Thessalonians?', 'He worked night and day so as not to be a burden to any of them', 'He performed many miracles', 'He fasted for forty days', 'He gave away all his money', 'a', '2 Thessalonians 3:8 — "Neither did we eat any man''s bread for nought; but wrought with labour and travail night and day, that we might not be chargeable to any of you."'),
('2 Thessalonians', 3, 'teens', 4, 'What does Paul say the Lord is faithful to do?', 'Stablish (establish) them and keep them from evil', 'Make them wealthy', 'Remove all their problems', 'Give them political power', 'a', '2 Thessalonians 3:3 — "the Lord is faithful, who shall stablish you, and keep you from evil."'),
('2 Thessalonians', 3, 'teens', 5, 'How does Paul describe the busybodies in the church?', 'They work not at all but are busybodies — meddling in others'' affairs instead of working', 'They are hard workers who take on too much', 'They are dedicated prayer warriors', 'They are enthusiastic evangelists', 'a', '2 Thessalonians 3:11 — "we hear that there are some which walk among you disorderly, working not at all, but are busybodies."'),
-- Adults
('2 Thessalonians', 3, 'adults', 1, 'What does Paul pray for regarding unreasonable and wicked men?', 'That he and his companions may be delivered from them, for all men have not faith', 'That they be struck down by God', 'That they be converted immediately', 'That they be imprisoned by the Romans', 'a', '2 Thessalonians 3:2 — "that we may be delivered from unreasonable and wicked men: for all men have not faith."'),
('2 Thessalonians', 3, 'adults', 2, 'What does Paul say was the purpose of his example of working?', 'To make himself an ensample (example) for them to follow, not because he had no right to support', 'Because he could not find donors', 'Because manual labor was required by Jewish law', 'Because the Thessalonians refused to support him', 'a', '2 Thessalonians 3:9 — "Not because we have not power, but to make ourselves an ensample unto you to follow us."'),
('2 Thessalonians', 3, 'adults', 3, 'What connection exists between idleness and the eschatological confusion in Thessalonica?', 'Some Thessalonians, believing Christ''s return was imminent, stopped working and became idle busybodies — Paul corrects both their theology and behavior', 'The idle were pagans who hadn''t yet converted', 'Idleness was a cultural norm in Thessalonica', 'The idle were wealthy patrons who didn''t need to work', 'a', '2 Thessalonians 3:10-12 connects the command to work with the correction of eschatological excitement leading to abandonment of daily responsibilities.'),
('2 Thessalonians', 3, 'adults', 4, 'What disciplinary measure does Paul prescribe for those who disobey this epistle?', 'Note that man and have no company with him, that he may be ashamed — yet admonish him as a brother, not an enemy', 'Excommunicate him permanently', 'Fine him and take his property', 'Report him to the civil authorities', 'a', '2 Thessalonians 3:14-15 — "note that man, and have no company with him, that he may be ashamed. Yet count him not as an enemy, but admonish him as a brother."'),
('2 Thessalonians', 3, 'adults', 5, 'What does Paul direct the Lord to do for their hearts?', '"The Lord direct your hearts into the love of God, and into the patient waiting for Christ"', '"The Lord fill your hearts with knowledge"', '"The Lord remove all fear from your hearts"', '"The Lord grant your hearts'' desires"', 'a', '2 Thessalonians 3:5 — "the Lord direct your hearts into the love of God, and into the patient waiting for Christ."'),
('2 Thessalonians', 3, 'adults', 6, 'What does Paul say about the tradition (teaching) they received from him?', 'They should withdraw from every brother who walks disorderly and not after the tradition received from the apostles', 'Traditions are optional guidelines', 'Only written traditions are authoritative', 'Traditions should be modified by each generation', 'a', '2 Thessalonians 3:6 — "withdraw yourselves from every brother that walketh disorderly, and not after the tradition which he received of us."'),
('2 Thessalonians', 3, 'adults', 7, 'How does Paul authenticate this letter?', 'He writes the salutation with his own hand, which is the token (sign) in every epistle', 'He seals it with his apostolic ring', 'He has two witnesses sign it', 'He sends it via a trusted courier only', 'a', '2 Thessalonians 3:17 — "The salutation of Paul with mine own hand, which is the token in every epistle: so I write."'),
('2 Thessalonians', 3, 'adults', 8, 'What comprehensive peace blessing does Paul give?', '"Now the Lord of peace himself give you peace always by all means"', '"May the God of war protect you from your enemies"', '"May the Lord give you financial peace"', '"Peace be upon Israel and the church"', 'a', '2 Thessalonians 3:16 — "Now the Lord of peace himself give you peace always by all means. The Lord be with you all."');
